import { atom, createStore } from 'jotai';
import CountDown from '@smartgmp-components/count-down';

const store = createStore();
const pageBaseAtom = atom({ campaignEndTime: Date.now() + 3 * 24 * 60 * 60 * 1000, groupName: '示例活动' });

export default function Page() {
  return <CountDown store={store} atomMap={{ pageBaseAtom }} />;
}

