import type { PrimitiveAtom } from 'jotai';

export interface PageBase {
  campaignEndTime: number;
  groupName: string;
}

export interface CountDownProps {
  textColor?: string;
  bgColor?: string;
  verticalOffsetDistance?: number;
  __designMode?: string;
  store?: any;
  atomMap?: {
    pageBaseAtom: PrimitiveAtom<PageBase>;
  };
}
